process_chain.block:

match $REQ.host "" && error --from lib "PC-TPL-ROUTE-0001";
match $REQ.path "" && error --from lib "PC-TPL-ROUTE-0001";

match $REQ.host "*.internal.example.com" && match $REQ.path "/api/*" && return --from lib "upstream_api";
match $REQ.path "/static/*" && return --from lib "upstream_static";

return --from lib "upstream_default";
